-- Blog migration for production (schema + data + production image URLs)
-- Generated: 2026-05-28T21:24:20.735Z
-- Posts: 5  |  Blocks: 34  |  Images: 6
-- Safe to run multiple times (fully idempotent).
-- Does NOT touch: products, user_profiles, customer_orders or any other table.
-- =============================================================================

-- ---------------------------------------------------------------------------
-- 1. blog_posts table
-- ---------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS blog_posts (
  id            uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
  title         text        NOT NULL,
  slug          text        NOT NULL UNIQUE,
  eyebrow       text,
  excerpt       text,
  cover_image   text,
  read_time     text,
  published_at  date,
  is_featured   boolean     NOT NULL DEFAULT false,
  published     boolean     NOT NULL DEFAULT false,
  show_in_list  boolean     NOT NULL DEFAULT true,
  created_at    timestamptz NOT NULL DEFAULT now()
);
ALTER TABLE blog_posts ADD COLUMN IF NOT EXISTS show_in_list boolean NOT NULL DEFAULT true;

-- ---------------------------------------------------------------------------
-- 2. blog_blocks table
-- ---------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS blog_blocks (
  id        uuid    PRIMARY KEY DEFAULT gen_random_uuid(),
  post_id   uuid    NOT NULL REFERENCES blog_posts(id) ON DELETE CASCADE,
  type      text    NOT NULL DEFAULT 'text',
  content   text,
  position  integer NOT NULL DEFAULT 1
);
CREATE INDEX IF NOT EXISTS blog_blocks_post_id_idx ON blog_blocks(post_id);
DO $$ DECLARE r RECORD; BEGIN FOR r IN (
  SELECT conname FROM pg_constraint c JOIN pg_class t ON c.conrelid = t.oid
  WHERE t.relname = 'blog_blocks' AND c.contype = 'c' AND pg_get_constraintdef(c.oid) ILIKE '%type%'
) LOOP EXECUTE format('ALTER TABLE blog_blocks DROP CONSTRAINT %I', r.conname); END LOOP; END; $$;
ALTER TABLE blog_blocks ADD CONSTRAINT blog_blocks_type_check CHECK (type IN ('text', 'image'));

-- ---------------------------------------------------------------------------
-- 3. Row-level security
-- ---------------------------------------------------------------------------
ALTER TABLE blog_posts  ENABLE ROW LEVEL SECURITY;
ALTER TABLE blog_blocks ENABLE ROW LEVEL SECURITY;
DO $$ BEGIN CREATE POLICY "public read published posts" ON blog_posts FOR SELECT USING (published = true); EXCEPTION WHEN duplicate_object THEN NULL; END $$;
DO $$ BEGIN CREATE POLICY "public read blocks of published posts" ON blog_blocks FOR SELECT USING (EXISTS (SELECT 1 FROM blog_posts p WHERE p.id = blog_blocks.post_id AND p.published = true)); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ---------------------------------------------------------------------------
-- 4. blog-images storage bucket
-- ---------------------------------------------------------------------------
INSERT INTO storage.buckets (id, name, public, file_size_limit, allowed_mime_types) VALUES ('blog-images', 'blog-images', true, 5242880, ARRAY['image/jpeg','image/png','image/webp','image/gif','image/avif']) ON CONFLICT (id) DO NOTHING;
DO $$ BEGIN CREATE POLICY "blog-images public read" ON storage.objects FOR SELECT USING (bucket_id = 'blog-images'); EXCEPTION WHEN duplicate_object THEN NULL; END $$;

