INSERT INTO blog_blocks (id, post_id, type, content, position) VALUES ('efe69ee2-be7e-4bc8-97d5-ca977e1967be', '3b29994e-f054-4ba9-b741-2af21df01bc7', 'text', '<p>хъуи  йхг ъ уи уъг хйг хй</p>', 3) ON CONFLICT (id) DO UPDATE SET type='text', content='<p>хъуи  йхг ъ уи уъг хйг хй</p>', position=3;
